from dataclasses import dataclass


@dataclass(frozen=True)
class SigningKey:
    key_id: str
    secret: bytes
    valid_from: int
    valid_until: int


class KeyRing:
    def __init__(self, keys: list[SigningKey], grace_seconds: int = 0):
        self._keys = list(keys)
        self.grace_seconds = grace_seconds

    def candidates(self, key_id: str, seen_at: int) -> list[SigningKey]:
        grace_end = seen_at + self.grace_seconds
        return [
            key
            for key in self._keys
            if (key.key_id == key_id and key.valid_from <= seen_at < key.valid_until)
            or (
                key.key_id == key_id
                and key.valid_until <= seen_at
                and seen_at < grace_end
            )
        ]
